use anyhow::Result;
use mvm_core::vm_backend::{VmBackend, VmCapabilities, VmId, VmInfo, VmStartConfig, VmStatus};

use crate::config::VMS_DIR;
use crate::shell::{run_in_vm, run_in_vm_stdout, run_in_vm_visible};
use crate::ui;
use crate::vm::{firecracker, microvm, network};

/// Configuration for a microvm.nix-based VM.
///
/// The runner directory contains scripts generated by microvm.nix
/// (e.g. `bin/microvm-run`, `bin/microvm-shutdown`) that manage the
/// full VM lifecycle including hypervisor invocation and TAP setup.
pub struct MicrovmNixConfig {
    /// VM name (user-provided or auto-generated).
    pub name: String,
    /// Network slot for this VM.
    pub slot: crate::config::VmSlot,
    /// Directory containing microvm.nix runner scripts (`bin/microvm-run`).
    pub runner_dir: String,
    /// Nix store revision hash.
    pub revision_hash: String,
    /// Original flake reference.
    pub flake_ref: String,
    /// Flake profile name.
    pub profile: Option<String>,
    /// Number of vCPUs (for status display).
    pub cpus: u32,
    /// Memory in MiB (for status display).
    pub memory: u32,
}

impl MicrovmNixConfig {
    /// Convert a backend-agnostic `VmStartConfig` into a microvm.nix config,
    /// allocating a network slot automatically.
    pub fn from_start_config(config: &VmStartConfig) -> Result<Self> {
        let runner_dir = config.runner_dir.clone().ok_or_else(|| {
            anyhow::anyhow!("microvm.nix backend requires runner_dir in VmStartConfig")
        })?;
        let slot = microvm::allocate_slot(&config.name)?;
        Ok(Self {
            name: config.name.clone(),
            slot,
            runner_dir,
            revision_hash: config.revision_hash.clone(),
            flake_ref: config.flake_ref.clone(),
            profile: config.profile.clone(),
            cpus: config.cpus,
            memory: config.memory_mib,
        })
    }
}

/// Backend that uses microvm.nix runner scripts for VM lifecycle.
///
/// Instead of manually calling the Firecracker API (boot-source, drives,
/// machine-config, etc.), this backend delegates to the runner scripts
/// that microvm.nix generates during `nix build`. The runner handles
/// hypervisor selection, TAP networking, and all API configuration.
pub struct MicrovmNixBackend;

impl VmBackend for MicrovmNixBackend {
    fn name(&self) -> &str {
        "microvm-nix"
    }

    fn capabilities(&self) -> VmCapabilities {
        VmCapabilities {
            pause_resume: false,
            snapshots: false,
            vsock: true,
            tap_networking: true,
        }
    }

    fn start(&self, config: &VmStartConfig) -> Result<VmId> {
        let nix_config = MicrovmNixConfig::from_start_config(config)?;
        self.start_nix(&nix_config)
    }

    fn stop(&self, id: &VmId) -> Result<()> {
        microvm::stop_vm(&id.0)
    }

    fn stop_all(&self) -> Result<()> {
        microvm::stop_all_vms()
    }

    fn status(&self, id: &VmId) -> Result<VmStatus> {
        let vms = microvm::list_vms()?;
        match vms.iter().find(|info| info.name.as_deref() == Some(&*id.0)) {
            Some(_) => Ok(VmStatus::Running),
            None => Ok(VmStatus::Stopped),
        }
    }

    fn list(&self) -> Result<Vec<VmInfo>> {
        let vms = microvm::list_vms()?;
        Ok(vms
            .into_iter()
            .filter_map(|info| {
                let name = info.name.clone()?;
                Some(VmInfo {
                    id: VmId(name.clone()),
                    name,
                    status: VmStatus::Running,
                    guest_ip: info.guest_ip,
                    cpus: info.cpus,
                    memory_mib: info.memory,
                    profile: info.profile,
                    revision: info.revision,
                    flake_ref: info.flake_ref,
                })
            })
            .collect())
    }

    fn logs(&self, id: &VmId, lines: u32, hypervisor: bool) -> Result<String> {
        let abs_vms = run_in_vm_stdout(&format!("echo {}", VMS_DIR))?;
        let abs_vms = abs_vms.trim();
        let filename = if hypervisor {
            "firecracker.log"
        } else {
            "console.log"
        };
        let log_file = format!("{}/{}/{}", abs_vms, id.0, filename);
        run_in_vm_stdout(&format!(
            "tail -n {} {} 2>/dev/null || true",
            lines, log_file
        ))
    }

    fn is_available(&self) -> Result<bool> {
        // microvm.nix runner is available if nix is installed
        let output = run_in_vm_stdout("command -v nix >/dev/null 2>&1 && echo yes || echo no")?;
        Ok(output.trim() == "yes")
    }

    fn install(&self) -> Result<()> {
        // Nix must already be installed; runner scripts are built via nix build
        ui::info("microvm.nix backends require Nix. Use 'mvmctl setup' to install.");
        Ok(())
    }
}

impl MicrovmNixBackend {
    /// Start a VM from a fully-populated `MicrovmNixConfig`.
    fn start_nix(&self, config: &MicrovmNixConfig) -> Result<VmId> {
        let slot = &config.slot;
        let abs_dir = run_in_vm_stdout(&format!("echo {}/{}", VMS_DIR, config.name))?;
        let pid_file = format!("{}/fc.pid", abs_dir);

        if firecracker::is_vm_running(&pid_file)? {
            ui::info(&format!("VM '{}' is already running.", config.name));
            return Ok(VmId(config.name.clone()));
        }

        // Ensure bridge network
        network::bridge_ensure()?;
        network::tap_create(slot)?;

        // Start the VM via microvm.nix runner script
        ui::info(&format!(
            "Starting VM '{}' via microvm.nix runner...",
            config.name
        ));
        run_in_vm_visible(&format!(
            r#"
            mkdir -p {dir}
            sudo {runner}/bin/microvm-run \
                >{dir}/console.log 2>{dir}/firecracker.log &
            echo $! > {dir}/fc.pid

            echo "[mvm] Waiting for VM process..."
            sleep 1
            if [ -f {dir}/fc.pid ] && kill -0 $(cat {dir}/fc.pid) 2>/dev/null; then
                echo "[mvm] VM started."
            else
                echo "[mvm] WARNING: VM process may not be running." >&2
            fi
            "#,
            dir = abs_dir,
            runner = config.runner_dir,
        ))?;

        // Persist run info
        write_run_info(config, &abs_dir)?;

        ui::banner(&[
            &format!("MicroVM '{}' is running! (microvm.nix)", config.name),
            "",
            &format!("  Guest IP: {}", slot.guest_ip),
            &format!("  Revision: {}", config.revision_hash),
            "",
            &format!("Use 'mvmctl stop {}' to shut down.", config.name),
        ]);

        Ok(VmId(config.name.clone()))
    }
}

/// Persist run info for a microvm.nix-started VM.
fn write_run_info(config: &MicrovmNixConfig, abs_dir: &str) -> Result<()> {
    let info = crate::config::RunInfo {
        schema_version: 1,
        mode: "microvm-nix".to_string(),
        name: Some(config.name.clone()),
        revision: Some(config.revision_hash.clone()),
        flake_ref: Some(config.flake_ref.clone()),
        guest_ip: Some(config.slot.guest_ip.clone()),
        profile: config.profile.clone(),
        guest_user: String::new(),
        cpus: config.cpus,
        memory: config.memory,
        ports: vec![],
    };

    let mut json_value = serde_json::to_value(&info)?;
    if let Some(obj) = json_value.as_object_mut() {
        obj.insert(
            "slot_index".to_string(),
            serde_json::Value::Number(config.slot.index.into()),
        );
    }

    let json = serde_json::to_string(&json_value)?;
    run_in_vm(&format!(
        "echo '{}' > {dir}/run-info.json",
        json,
        dir = abs_dir,
    ))?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_microvm_nix_backend_name() {
        let backend = MicrovmNixBackend;
        assert_eq!(backend.name(), "microvm-nix");
    }

    #[test]
    fn test_microvm_nix_capabilities() {
        let backend = MicrovmNixBackend;
        let caps = backend.capabilities();
        assert!(!caps.pause_resume);
        assert!(!caps.snapshots);
        assert!(caps.vsock);
        assert!(caps.tap_networking);
    }
}
